data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist in the framework. Here's what you actually use for boundary/comparison testing:

## MSTest Numeric Assertions

| Need | MSTest Approach |
|------|----------------|
| Greater than | `Assert.IsTrue(value > threshold, "message")` |
| In range | `Assert.IsTrue(value >= min && value <= max)` |
| Float equality | `Assert.AreEqual(expected, actual, delta)` |
| Exceptions | `Assert.ThrowsException<T>(() => ...)` |

## Example tests for your `ScoreCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        double result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        double result = _calc.CalculatePercentage(7, 10);
        // No Assert.IsInRange — use Assert.IsTrue instead
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100, got {result}");
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsGreaterThanZero()
    {
        double result = _calc.CalculatePercentage(1, 10);
        // No Assert.IsGreaterThan — use Assert.IsTrue
        Assert.IsTrue(result > 0.0, $"Expected > 0, got {result}");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_BoundaryValues(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void NormalizeScore_ClampedTo100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ResultNeverExceeds100()
    {
        double result = _calc.NormalizeScore(200, 50);
        Assert.IsTrue(result <= 100.0,
            $"Expected <= 100, got {result}");
    }
}
```

**Key takeaway:** For comparisons and ranges in MSTest, use `Assert.IsTrue(condition, message)` with a descriptive failure message. The `delta` overload of `Assert.AreEqual` handles floating-point tolerance. If you want more expressive syntax, consider adding the **FluentAssertions** NuGet package, which provides `result.Should().BeInRange(0, 100)` and `result.Should().BeGreaterThan(0)`.
